INSERT INTO articles (id, title, slug, summary, body_html, cover_url, category_id, status, is_featured, is_pinned, sort_order, view_count, published_at, created_at, updated_at, seo_title, seo_description) VALUES (1, 'Cucumber Lime Cooler for Hot Afternoons', 'cucumber-lime-cooler-hot-afternoons', 'A crisp alcohol-free cooler built with cucumber, lime, mint, and sparkling water.', '<p>This cucumber lime cooler is designed for days when you want something bright, clean, and easy to build. Muddle cucumber with fresh lime juice and mint, then shake it with a little honey syrup before topping with chilled sparkling water.</p><p>Serve it over plenty of ice and finish with a cucumber ribbon. The result is refreshing without becoming too sweet, making it a reliable mocktail recipe for lunches, cookouts, and slow summer afternoons.</p>', '', 1, 'published', 1, 1, 1, 18420, '2026-06-29T10:00:00.000Z', '2026-07-17T09:36:26.465Z', '2026-07-17T09:36:26.465Z', 'Cucumber Lime Cooler Mocktail Recipe', 'Make a refreshing cucumber lime cooler with mint, honey syrup, and sparkling water.');
INSERT INTO article_tags (article_id, tag_id) VALUES (1, 1);
INSERT INTO article_tags (article_id, tag_id) VALUES (1, 2);
INSERT INTO article_tags (article_id, tag_id) VALUES (1, 3);
INSERT INTO articles (id, title, slug, summary, body_html, cover_url, category_id, status, is_featured, is_pinned, sort_order, view_count, published_at, created_at, updated_at, seo_title, seo_description) VALUES (2, 'How to Balance Sweetness and Citrus in Mocktails', 'balance-sweetness-citrus-mocktails', 'A practical flavor guide for adjusting sugar, acidity, dilution, and aroma in alcohol-free drinks.', '<p>Great mocktails need balance because there is no spirit to carry bitterness, body, or heat. Start by pairing one bright acid, such as lemon or lime, with a measured sweetener like simple syrup, honey syrup, or agave.</p><blockquote>Taste after dilution, not before. Ice and bubbles can soften both sweetness and acidity.</blockquote><p>If the drink feels flat, add a pinch of salt or a fragrant garnish. If it feels sharp, lengthen it with tea, soda water, or chilled juice rather than adding sugar immediately.</p>', '', 2, 'published', 0, 1, 2, 15105, '2026-06-28T09:30:00.000Z', '2026-07-17T09:36:26.465Z', '2026-07-17T09:36:26.465Z', 'How to Balance Sweetness and Citrus in Mocktails', 'Learn how to balance sweetness, acidity, dilution, and aroma in alcohol-free drinks.');
INSERT INTO article_tags (article_id, tag_id) VALUES (2, 2);
INSERT INTO article_tags (article_id, tag_id) VALUES (2, 6);
INSERT INTO articles (id, title, slug, summary, body_html, cover_url, category_id, status, is_featured, is_pinned, sort_order, view_count, published_at, created_at, updated_at, seo_title, seo_description) VALUES (3, 'Three Alcohol-Free Classics Every Home Bar Needs', 'three-alcohol-free-classics-home-bar', 'A starter set of classic mocktail formats for building dependable drinks without alcohol.', '<p>A strong alcohol-free home bar starts with repeatable formats. A citrus spritz, a ginger highball, and a non-alcoholic sour can cover most occasions while teaching the basics of bubbles, spice, texture, and acidity.</p><p>Keep fresh citrus, good tonic or soda, ginger beer, tea concentrates, and one or two syrups on hand. From there, you can adjust each classic with herbs, bitters-style aromatics, or seasonal fruit.</p>', '', 3, 'published', 0, 0, 3, 12680, '2026-06-27T13:10:00.000Z', '2026-07-17T09:36:26.465Z', '2026-07-17T09:36:26.465Z', 'Three Alcohol-Free Classic Mocktails', 'Build a better alcohol-free home bar with three classic mocktail formats.');
INSERT INTO article_tags (article_id, tag_id) VALUES (3, 1);
INSERT INTO article_tags (article_id, tag_id) VALUES (3, 5);
INSERT INTO articles (id, title, slug, summary, body_html, cover_url, category_id, status, is_featured, is_pinned, sort_order, view_count, published_at, created_at, updated_at, seo_title, seo_description) VALUES (4, 'Sparkling Berry Punch for Easy Party Drinks', 'sparkling-berry-punch-party-drinks', 'A colorful batch mocktail with berries, citrus, tea, and sparkling water for gatherings.', '<p>Party drinks should be easy to pour, easy to scale, and good-looking in a pitcher. This sparkling berry punch combines muddled berries, lemon juice, chilled hibiscus tea, and a light syrup base.</p><p>Mix the fruit, citrus, tea, and syrup ahead of time, then add sparkling water right before serving. Garnish each glass with berries and a lemon wheel so the drink feels composed without slowing down the host.</p>', '', 4, 'published', 0, 0, 4, 11290, '2026-06-26T08:00:00.000Z', '2026-07-17T09:36:26.465Z', '2026-07-17T09:36:26.465Z', 'Sparkling Berry Punch Party Mocktail', 'Make a colorful alcohol-free berry punch for parties, gatherings, and summer events.');
INSERT INTO article_tags (article_id, tag_id) VALUES (4, 3);
INSERT INTO article_tags (article_id, tag_id) VALUES (4, 4);
INSERT INTO articles (id, title, slug, summary, body_html, cover_url, category_id, status, is_featured, is_pinned, sort_order, view_count, published_at, created_at, updated_at, seo_title, seo_description) VALUES (5, 'Flavor Guide: Herbs That Make Citrus Drinks Pop', 'herbs-that-make-citrus-drinks-pop', 'Use mint, basil, rosemary, and thyme to add aroma and structure to citrus mocktails.', '<p>Herbs can make a simple citrus mocktail feel complete. Mint brings lift, basil adds a soft savory note, rosemary gives piney structure, and thyme works well with grapefruit or honey.</p><ul><li>Clap delicate herbs before garnishing to release aroma.</li><li>Steep woody herbs into syrup for stronger flavor.</li><li>Pair one herb with one citrus first, then add complexity.</li></ul>', '', 2, 'published', 0, 0, 5, 8730, '2026-06-25T16:20:00.000Z', '2026-07-17T09:36:26.465Z', '2026-07-17T09:36:26.465Z', 'Best Herbs for Citrus Mocktails', 'A flavor guide to using mint, basil, rosemary, and thyme in citrus mocktails.');
INSERT INTO article_tags (article_id, tag_id) VALUES (5, 2);
INSERT INTO article_tags (article_id, tag_id) VALUES (5, 6);
INSERT INTO articles (id, title, slug, summary, body_html, cover_url, category_id, status, is_featured, is_pinned, sort_order, view_count, published_at, created_at, updated_at, seo_title, seo_description) VALUES (6, 'Watermelon Mint Spritz for Summer Brunch', 'watermelon-mint-spritz-summer-brunch', 'A light, healthy mocktail with watermelon juice, mint, lime, and bubbles.', '<p>This watermelon mint spritz keeps brunch drinks light while still feeling festive. Blend fresh watermelon, strain the juice, then shake it with lime and mint before topping with sparkling water.</p><p>For a cleaner finish, chill the watermelon juice before mixing and avoid over-sweetening. Ripe watermelon usually brings enough natural sugar, so a small splash of syrup is only needed when the fruit is mild.</p>', '', 1, 'published', 0, 0, 6, 7425, '2026-06-24T11:45:00.000Z', '2026-07-17T09:36:26.465Z', '2026-07-17T09:36:26.465Z', 'Watermelon Mint Spritz Mocktail', 'Make a light summer mocktail with watermelon juice, mint, lime, and sparkling water.');
INSERT INTO article_tags (article_id, tag_id) VALUES (6, 1);
INSERT INTO article_tags (article_id, tag_id) VALUES (6, 3);
INSERT INTO article_tags (article_id, tag_id) VALUES (6, 6);
